import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Header from '../components/Header';

export default function Payments() {
  const [list, setList] = useState([]);
  useEffect(() => {
    axios.get('/payments').then(r => setList(r.data));
  }, []);

  return (
    <>
      <Header title="Payments" />
      <main className="p-8">
        <ul className="bg-white rounded shadow-lg divide-y">
          {list.map(p => (
            <li key={p.id} className="px-6 py-4 flex justify-between">
              <span>{p.id}</span>
              <span className="font-bold">{(p.amount/100).toFixed(2)} €</span>
              <span className={p.status === 'succeeded' ? 'text-green-600' : 'text-red-600'}>
                {p.status}
              </span>
            </li>
          ))}
        </ul>
      </main>
    </>
  );
}
